package policy

import (
	"fmt"

	admissionv1 "k8s.io/api/admission/v1"
	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/util/validation/field"
)

// Validate validates an admission request against Terravault security policies.
func Validate(request *admissionv1.AdmissionRequest, config PolicyConfig) *ValidationResult {
	result := &ValidationResult{
		Allowed: true,
		Warnings: make([]string, 0),
	}

	// Only validate CREATE and UPDATE operations
	if request.Operation != admissionv1.Create && request.Operation != admissionv1.Update {
		return result
	}

	// Decode the pod from the admission request
	pod := &corev1.Pod{}
	if _, _, err := codec.DecodeRaw(request.Object.Raw, pod); err != nil {
		return &ValidationResult{
			Allowed: false,
			Reason:  fmt.Sprintf("Failed to decode pod: %v", err),
		}
	}

	// Apply all validation rules
	allPaths := field.NewPath("pod")

	// 1. Check for privileged containers
	if config.DenyPrivileged {
		privilegedErrors := validatePrivilegedContainers(pod, allPaths)
		if len(privilegedErrors) > 0 {
			result.Allowed = false
			result.Reason = "Privileged containers are not allowed"
			// Return first error
			for _, err := range privilegedErrors {
				if err != nil {
					result.Reason += fmt.Sprintf(": %s", err)
					break
				}
			}
		}
	}

	// 2. Check for host network access
	if config.DenyHostNetwork {
		if err := validateHostNetwork(pod, allPaths); err != nil {
			result.Allowed = false
			result.Reason = "Host network access is not allowed"
		}
	}

	// 3. Check resource limits
	if config.EnforceResourceLimits {
		resourceErrors := validateResourceLimits(pod, allPaths)
		if len(resourceErrors) > 0 {
			result.Allowed = false
			result.Reason = "Resource limits are required on all containers"
			// Return first error
			for _, err := range resourceErrors {
				if err != nil {
					result.Reason += fmt.Sprintf(": %s", err)
					break
				}
			}
		}
	}

	// 4. Check security context
	if config.EnforceSecurityContext {
		if err := validateSecurityContext(pod, allPaths); err != nil {
			result.Allowed = false
			result.Reason = "Security context requirements not met"
		}
	}

	return result
}

// validatePrivilegedContainers checks that no container is privileged.
func validatePrivilegedContainers(pod *corev1.Pod, fieldPath *field.Path) field.ErrorList {
	allErrs := field.ErrorList{}

	for i, container := range pod.Spec.InitContainers {
		allErrs = append(allErrs, validateContainerPrivileged(container, fieldPath.Key("initContainers").Index(i))...)
	}

	for i, container := range pod.Spec.Containers {
		allErrs = append(allErrs, validateContainerPrivileged(container, fieldPath.Key("containers").Index(i))...)
	}

	return allErrs
}

// validateContainerPrivileged checks a single container for privileged mode.
func validateContainerPrivileged(container corev1.Container, fieldPath *field.Path) field.ErrorList {
	allErrs := field.ErrorList{}
	if container.SecurityContext != nil && container.SecurityContext.Privileged != nil && *container.SecurityContext.Privileged {
		allErrs = append(allErrs, field.Forbidden(
			fieldPath.Child("securityContext", "privileged"),
			"privileged containers are not allowed",
		))
	}
	return allErrs
}

// validateHostNetwork checks that pod is not using host network.
func validateHostNetwork(pod *corev1.Pod, fieldPath *field.Path) field.ErrorList {
	allErrs := field.ErrorList{}
	if pod.Spec.HostNetwork {
		allErrs = append(allErrs, field.Forbidden(
			fieldPath.Child("hostNetwork"),
			"host network access is not allowed",
		))
	}
	return allErrs
}

// validateResourceLimits checks that all containers have CPU and memory limits.
func validateResourceLimits(pod *corev1.Pod, fieldPath *field.Path) field.ErrorList {
	allErrs := field.ErrorList{}

	// Check init containers
	for i, container := range pod.Spec.InitContainers {
		allErrs = append(allErrs, validateContainerResources(container, fieldPath.Key("initContainers").Index(i))...)
	}

	// Check regular containers
	for i, container := range pod.Spec.Containers {
		allErrs = append(allErrs, validateContainerResources(container, fieldPath.Key("containers").Index(i))...)
	}

	return allErrs
}

// validateContainerResources checks a single container for required resource limits.
func validateContainerResources(container corev1.Container, fieldPath *field.Path) field.ErrorList {
	allErrs := field.ErrorList{}

	if container.Resources.Limits == nil || container.Resources.Limits.Cpu() == nil || container.Resources.Limits.Memory() == nil {
		allErrs = append(allErrs, field.Required(
			fieldPath.Child("resources", "limits"),
			"CPU and memory limits are required for all containers",
		))
	}

	return allErrs
}

// validateSecurityContext checks that pod and containers have proper security context.
func validateSecurityContext(pod *corev1.Pod, fieldPath *field.Path) field.ErrorList {
	allErrs := field.ErrorList{}

	// Check pod-level security context
	if pod.Spec.SecurityContext != nil && pod.Spec.SecurityContext.Privileged != nil && *pod.Spec.SecurityContext.Privileged {
		allErrs = append(allErrs, field.Forbidden(
			fieldPath.Child("securityContext", "privileged"),
			"pod-level privileged security context is not allowed",
		))
	}

	// Check init containers
	for i, container := range pod.Spec.InitContainers {
		allErrs = append(allErrs, validateContainerSecurityContext(container, fieldPath.Key("initContainers").Index(i))...)
	}

	// Check regular containers
	for i, container := range pod.Spec.Containers {
		allErrs = append(allErrs, validateContainerSecurityContext(container, fieldPath.Key("containers").Index(i))...)
	}

	return allErrs
}

// validateContainerSecurityContext checks a single container for required security context settings.
func validateContainerSecurityContext(container corev1.Container, fieldPath *field.Path) field.ErrorList {
	allErrs := field.ErrorList{}

	// Check runAsNonRoot
	if container.SecurityContext == nil || container.SecurityContext.RunAsNonRoot == nil || !*container.SecurityContext.RunAsNonRoot {
		allErrs = append(allErrs, field.Required(
			fieldPath.Child("securityContext", "runAsNonRoot"),
			"runAsNonRoot must be true for all containers",
		))
	}

	// Check privilege escalation
	if container.SecurityContext != nil && container.SecurityContext.AllowPrivilegeEscalation != nil && *container.SecurityContext.AllowPrivilegeEscalation {
		allErrs = append(allErrs, field.Forbidden(
			fieldPath.Child("securityContext", "allowPrivilegeEscalation"),
			"privilege escalation is not allowed",
		))
	}

	return allErrs
}

