	"net/http"
	"os"

	admissionv1 "k8s.io/api/admission/v1"
	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/serializer"
	"k8s.io/klog/v2"

	"github.com/terravault/admission-controller/pkg/policy"
)

var (
	runtimeScheme = runtime.NewScheme()
	codecs        = serializer.NewCodecFactory(runtimeScheme)
)

func init() {
	_ = corev1.AddToScheme(runtimeScheme)
}

func main() {
	certFile := os.Getenv("TLS_CERT_FILE")
	keyFile := os.Getenv("TLS_KEY_FILE")
	port := os.Getenv("WEBHOOK_PORT")
	if port == "" {
		port = "8443"
	}

	// Initialize policy configuration
	config := policy.PolicyConfig{
		EnforceResourceLimits:      true,
		EnforceSecurityContext:     true,
		DenyPrivileged:             true,
		DenyHostNetwork:            true,
	}

	// Create validator
	validator := &policy.Validator{}

	klog.Infof("Starting Terravault admission webhook on port %s", port)

	// Register webhook handler
	http.HandleFunc("/validate", func(w http.ResponseWriter, r *http.Request) {
		var admissionReview admissionv1.AdmissionReview

		body, err := io.ReadAll(r.Body)
		if err != nil {
			klog.Errorf("Could not read request body: %v", err)
			http.Error(w, "Could not read request body", http.StatusBadRequest)
			return
		}

		if len(body) == 0 {
			klog.Errorf("empty request body")
			http.Error(w, "empty request body", http.StatusBadRequest)
			return
		}

		if _, _, err := codecs.UniversalDeserializer().Decode(body, nil, &admissionReview); err != nil {
			klog.Errorf("could not decode admission request: %v", err)
			http.Error(w, "could not decode admission request", http.StatusBadRequest)
			return
		}

		if admissionReview.Request == nil {
			klog.Errorf("malformed admission request: missing request")
			http.Error(w, "malformed admission request", http.StatusBadRequest)
			return
		}

		// Validate the admission request
		request := admissionReview.Request
		klog.V(4).Infof("Received admission request: %+v", request)

		admissionResponse := &admissionv1.AdmissionResponse{
			UID:     request.UID,
			Allowed: true,
		}

		// Decode the pod
		pod := &corev1.Pod{}
		if _, _, err := codecs.UniversalDeserializer().Decode(request.Object.Raw, nil, pod); err != nil {
			admissionResponse.Allowed = false
			admissionResponse.Result = &metav1.Status{
				Status:  metav1.StatusFailure,
				Message: fmt.Sprintf("could not decode pod: %v", err),
				Code:    http.StatusBadRequest,
			}
			admissionReview.Response = admissionResponse
			klog.Errorf("error decoding pod: %v", err)
		} else {
			// Run validation
			result := policy.Validate(request, config)
			admissionResponse.Allowed = result.Allowed

			if !result.Allowed {
				admissionResponse.Result = &metav1.Status{
					Status:  metav1.StatusFailure,
					Message: result.Reason,
					Code:    http.StatusForbidden,
				}
				klog.Warningf("admission denied: %s", result.Reason)
			} else {
				klog.Infof("admission allowed for pod: %s/%s", pod.Namespace, pod.Name)
			}
		}

		admissionReview.Response = admissionResponse

		// Encode the response
		responseBytes, err := json.Marshal(admissionReview)
		if err != nil {
			klog.Errorf("could not encode admission response: %v", err)
			http.Error(w, "could not encode admission response", http.StatusInternalServerError)
			return
		}

		w.Header().Set("Content-Type", "application/json")
		w.Write(responseBytes)
	})

	server := &http.Server{
		Addr: fmt.Sprintf(":%s", port),
	}

	if certFile != "" && keyFile != "" {
		klog.Fatal(server.ListenAndServeTLS(certFile, keyFile))
	} else {
		klog.Warning("Running without TLS - development mode only")
		klog.Fatal(server.ListenAndServe())
	}
}
